A debounce function limits how often a function can be executed by delaying its invocation until after a specified wait time has passed since the last time it was called.

```javascript
function debounce(func, delay) {
  let timeoutId;
  return function (...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(this, args), delay);
  };
}

// Example: Log user input only after they stop typing for 500ms
const debouncedLog = debounce((text) => {
  console.log('Input value:', text);
}, 500);

// Simulate input events
debouncedLog('h');     // won't log immediately
debouncedLog('he');    // still waiting...
debouncedLog('hel');   // still waiting...
// After 500ms of no calls, it logs: "Input value: hel"
```
